{% block body %}
    <div class=\"container\">
    <h1>Couleur index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                <th>Id</th>
                <th>Nom</th>
                <th>Statut</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for couleur in couleurs %}
            <tr>
                <td>{{ couleur.id }}</td>
                <td>{{ couleur.nom }}</td>
                <td>{{ couleur.statut ? 'Yes' : 'No' }}</td>
                <td>
                    <a href=\"{{ path('couleur_show', {'id': couleur.id}) }}\"><button class=\"btn btn-outline-dark\">Voir</button></a>
                    <a href=\"{{ path('couleur_edit', {'id': couleur.id}) }}\"><button class=\"btn btn-outline-dark\">Edition</button></a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"4\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>

    <a href=\"{{ path('couleur_new') }}\">Create new</a>
    </div>
{% endblock %}", "admin/couleur/index.html.twig", "D:\\Github\\Groupe6\\symfony\\projetLunettes\\templates\\admin\\couleur\\index.html.twig");
